import { useState, useCallback } from "react"
import "./index.css"

// --- Character Sets ---
const UPPERCASE = "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
const LOWERCASE = "abcdefghijklmnopqrstuvwxyz"
const NUMBERS = "0123456789"
const SYMBOLS = "!@#$%^&*()-_+=<>?/`~[]{}\|\\`~"

/**
 * Generates a random password based on current state.
 * @param length Min length for password.
 * @param includesUppercase If true, includes uppercase letters.
 * @param includesLowercase If true, includes lowercase letters.
 * @param includesNumbers If true, includes numbers.
 * @param includesSymbols If true, includes symbols.
 * @returns A random string of specified length.
 */
const generatePassword = useCallback(
  (length: number, includeUppercase: boolean, includeLowercase: boolean, includeNumbers: boolean, includeSymbols: boolean) => {
  let charSet = ""
  if (includeUppercase) charSet += UPPERCASE
  if (includeLowercase) charSet += LOWERCASE
  if (includeNumbers) charSet += NUMBERS
  if (includeSymbols) charSet += SYMBOLS

  if (!charSet) return "Error: Must select at least one character type."

  let result = ""
  for (let i = 0; i < length; i++) {
    result += charSet.charAt(Math.floor(Math.random() * charSet.length))
  }
return result
}, [])

function App() {
  const [length, setLength] = useState(12)
  const [uppercase, setUppercase] = useState(true)
  const [lowercase, setLowercase] = useState(true)
  const [numbers, setNumbers] = useState(true)
  const [symbols, setSymbols] = useState(true)
  const [password, setPassword] = useState("")

const generatePassword = useCallback(() => {
  const newPass = generatePassword(length, uppercase, lowercase, numbers, symbols)
setPassword(newPass)
}, [length, uppercase, lowercase, numbers, symbols])

const copyToClipboard = useCallback(() => {
  navigator.clipboard?.writeText(password)
  setMessage("Copied to clipboard!")
setTimeout(() => setMessage(""), 2000)
}, [password])

const [message, setMessage] = useState("")

return (
  <div className="min-h-screen bg-0 text-white">
  <div className="container py-16 md:py-24">
    <div className="max-w-xl mx-auto">
      <h1 className="text-4xl md:text-5xl font-extrabold tracking-tight mb-4">
        Password Generator
      </h1>
      <p className="text-xl text-muted mb-12 max-w-md mb-8">
        Generates a strong, random password based on your selected criteria.
      </p>

      {/* Character Type Toggles */}
      <div className="grid grid-cols-2 gap-6 mb-12 p-6 bg-1 rounded-xl border border-transparent transition-all duration-300 hover:border-accent/20">
        <label className="flex items-center cursor-pointer">
          <input
            type="checkbox"
            checked={uppercase}
            onChange={(e) => setUppercase(e.target.checked)}
            className="form-checkbox h-5 w-5 text-accent bg-0/1 border-transparent focus:ring-2 focus:ring-offset-2 focus:ring-accent"
          />
          <span className="ml-3 text-sm font-medium">Uppercase Letters</span>
        </label>

        <label className="flex items-center cursor-pointer">
          <input
            type="checkbox"
            checked={lowercase}
            onChange={(e) => setLowercase(e.target.checked)}
            className="form-checkbox h-5 w-5 text-accent bg-0/1 border-transparent focus:ring-2 focus:ring-offset-2 focus:ring-accent"
          />
          <span className="ml-3 text-sm font-medium">Lowercase Letters</span>
        </label>

        <label className="flex items-center cursor-pointer">
          <input
            type="checkbox"
            checked={numbers}
            onChange={(e) => setNumbers(e.target.checked)}
            className="form-checkbox h-5 w-5 text-accent bg-0/1 border-transparent focus:ring-2 focus:ring-offset-2 focus:ring-accent"
          />
          <span className="ml-3 text-xs font-medium">Numbers</span>
        </label>

        <label className="flex items-center cursor-pointer">
          <input
            type="checkbox"
            checked={symbols}
            onChange={(e) => setSymbols(e.target.checked)}
            className="form-checkbox h-5 w-5 text-accent bg-0/1 border-transparent focus:ring-2 focus:ring-offset-2 focus:ring-accent"
          />
          <span className="ml-3 text-xs font-medium">Symbols</span>
        </label>
      </div>

      {/* Length Slider */}
      <div className="mb-12 p-6 bg-1 rounded-xl border border-transparent transition-all duration-300 hover:border-accent/10">
        <div className="flex justify-between items-center mb-4">
          <label htmlFor="length" className="text-sm font-medium">Password Length</label>
          <span className="text-lg font-bold">{length}</span>
        </div>
        <input
          id="length"
          type="range"
          min={8}
          max={32}
          value={length}
          onChange={(e) => setLength(parseInt(e.target.value))}
          className="w-full appearance-none h-2 bg-0/1 rounded-lg [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:bg-accent [&::-webkit-slider-thumb]:h-6 [&::-webkit-slider-thumb]:w-2 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:transition-all duration-200 focus:ring-2 focus:ring-offset-2 focus:ring-accent"
          min={8}
          max={32}
        />
      </div>

      {/* Generate Button */}
      <button
        onClick={generatePassword}
        className="w-full py-4 px-6 rounded-xl text-lg font-bold transition-all duration-200 hover:shadow-glow active:scale-[0.98] focus:outline-none focus:ring-4 focus:ring-offset-2 focus:ring-accent disabled:opacity-50"
        disabled={!uppercase && !lowercase && !numbers && !symbols}
      >
        Generate Password
      </button>

      {/* Display Result Card */}
      <div className={`mt-12 ${password ? 'animate-in animate-scale' : ''}`}>
        <div className="bg-1 p-8 rounded-2xl border border-transparent transition-all duration-500 hover:border-accent/20">
          <div className="flex justify-between items-center mb-4">
            <p className="text-sm font-semibold tracking-wider uppercase">Generated Password</p>
            <button
              onClick={copyToClipboard}
              className="flex items-center gap-1 px-3 py-2 text-sm font-medium rounded-lg transition-all duration-200 hover:bg-accent/10 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-accent"
            >
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2" className="w-5 h-5">
                <path d="M16 8l-8 8L4 16v-4h16zM12 2c-3.31 0-6 2-6 6s2 6 6 6 6-6-6-6V2z"/>
              </svg>
              Copy
            </button>
          </div>

          <div
            className={`flex items-center gap-2 rounded-lg p-3 bg-0/1 transition-all duration-500 ${password ? 'animate-in animate-scale' : ''}`}
          >
            <span className="text-sm font-mono tracking-wider select-all">
              {password}
            </span>
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2" className="w-5 h-5 transform rotate-90">
                <path d="M12 2C6 2 2 6 2 12s4 10 12 12c6 6 12 12 12-12S22 10 18 2zM12 12v-6c0-3.31-2-6-6-6s-6 5-6 6v6h12c6 0 6-4 6-6z"/>
            </svg>
          </div>
        </div>

        {/* Message Toast */}
        <div className={`fixed top-4 right-4 z-50 p-3 rounded-xl text-sm font-medium transition-all duration-300 ${message ? 'animate-in animate-from-top opacity-0 scale-95' : 'opacity-100 translate-y-0'} ${message.includes('Copied') ? 'bg-green-600/20 border-green-700/30 text-green-200' : message.includes('Error') ? 'bg-red-700/20 border-red-800/30 text-red-100' : 'bg-0/1 border-transparent hover:border-accent/10'}`}
          role="alert"
        >
          {message}
        </div>
      </div>
    </div>
  </div>
)}
